import React, { useState, useEffect, useCallback } from 'react';
import { User, MapPin, Package, LogOut, X, Moon, Sun, ArrowLeft, Plus, Edit2, Trash2, Truck } from 'lucide-react';
import { toast } from 'react-toastify';
import api from '../../api/api';
import AddressModal from './AddressModal';
import ProfileModal from './ProfileModal';
import { useCart } from '../../context/CartContext';
import '../../assets/styles/UserSidebar.css';
import OrderTracker from '../orders/OrderTracker';


const UserSidebar = ({ isOpen, onClose }) => {
  const { setIsCartOpen } = useCart();
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [activeView, setActiveView] = useState('menu');
  const [user, setUser] = useState(null);
  const [addresses, setAddresses] = useState([]);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(false);

  // Modal States
  const [isAddressModalOpen, setIsAddressModalOpen] = useState(false);
  const [addressModalData, setAddressModalData] = useState(null);
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);

  const fetchProfile = useCallback(async () => {
    try {
      const data = await api.get('/api/auth/profile');
      if (data.success) {
        setUser(data.user);
      }
    } catch (err) {
      console.error('Failed to fetch profile', err);
    }
  }, []);

  const fetchAddresses = useCallback(async () => {
    try {
      const data = await api.get('/api/address');
      if (data.success) {
        setAddresses(data.addresses);
      }
    } catch (err) {
      console.error('Failed to fetch addresses', err);
    }
  }, []);

  const fetchOrders = useCallback(async () => {
    setLoading(true);
    try {
      const data = await api.get('/api/order');
      if (data.success) {
        setOrders(data.orders);
      }
    } catch (err) {
      console.error('Failed to fetch orders', err);
      toast.error('Failed to load order history');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (isOpen) {
      fetchProfile();
      fetchAddresses();
      fetchOrders();
      setActiveView('menu');
    }
  }, [isOpen, fetchProfile, fetchAddresses, fetchOrders]);

  useEffect(() => {
    setIsDarkMode(document.body.classList.contains('dark-theme'));
  }, [isOpen]);

  const toggleTheme = () => {
    document.body.classList.toggle('dark-theme');
    const newMode = document.body.classList.contains('dark-theme');
    setIsDarkMode(newMode);
    toast.success(newMode ? 'Dark Theme enabled' : 'Light Theme enabled');
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('loginTimestamp');
    toast.info('You have securely logged out.');
    window.dispatchEvent(new Event('authChange'));
    onClose();
  };

  const handleProfileUpdateSuccess = () => {
    fetchProfile();
    onClose(); // Close sidebar
  };

  // --- Simulation Helper ---
  const simulateStatus = (orderId) => {
    const statusOrder = ['Order Placed', 'In Transit', 'Out for Delivery', 'Delivered'];
    setOrders(prev => prev.map(o => {
      if (o.id === orderId) {
        const nextIdx = (statusOrder.indexOf(o.status) + 1) % statusOrder.length;
        return { ...o, status: statusOrder[nextIdx] };
      }
      return o;
    }));
  };

  // --- Address CRUD ---

  const handleAddAddress = async (formData) => {
    try {
      const data = await api.post('/api/address', formData);
      if (data.success) {
        toast.success(data.message);
        setAddresses(prev => [...prev, data.address]);
        setIsAddressModalOpen(false);
        onClose(); // Close sidebar
      }
    } catch (err) {
      console.error('Failed to add address', err);
    }
  };

  const handleUpdateAddress = async (formData) => {
    try {
      const data = await api.put(`/api/address/${formData.id}`, formData);
      if (data.success) {
        toast.success(data.message);
        setAddresses(prev => prev.map(a => a.id === formData.id ? data.address : a));
        setIsAddressModalOpen(false);
        onClose(); // Close sidebar
      }
    } catch (err) {
      console.error('Failed to update address', err);
    }
  };

  const handleDeleteAddress = async (id) => {
    try {
      const data = await api.delete(`/api/address/${id}`);
      if (data.success) {
        toast.success(data.message);
        setAddresses(prev => prev.filter(a => a.id !== id));
      }
    } catch (err) {
      console.error('Failed to delete address', err);
    }
  };

  const handleAddressModalSave = async (action, formData) => {
    if (action === 'add') {
      await handleAddAddress(formData);
    } else {
      await handleUpdateAddress(formData);
    }
  };

  const openAddressModal = (address = null) => {
    setAddressModalData(address);
    setIsAddressModalOpen(true);
  };

  const handleProfileClick = () => {
    setIsProfileModalOpen(true);
  };

  // --- Render Views ---

  const renderMenu = () => (
    <>
      <div className="sidebar-menu">
        <button className="menu-item" onClick={handleProfileClick}>
          <User size={20} />
          <span>Profile Details</span>
        </button>
        <button className="menu-item" onClick={() => setActiveView('addresses')}>
          <MapPin size={20} />
          <span>Saved Addresses</span>
        </button>
        <button className="menu-item" onClick={() => setActiveView('orders')}>
          <Package size={20} />
          <span>Order History</span>
        </button>
      </div>
      <div className="sidebar-footer">
        <button className="theme-toggle-btn" onClick={toggleTheme}>
          {isDarkMode ? <><Sun size={20} /><span>Switch to Light Mode</span></> : <><Moon size={20} /><span>Switch to Dark Mode</span></>}
        </button>
        <button className="logout-btn" onClick={handleLogout}>
          <LogOut size={20} /><span>Log Out</span>
        </button>
      </div>
    </>
  );

  const renderAddresses = () => (
    <div className="sidebar-subview">
      <button className="back-btn" onClick={() => setActiveView('menu')}><ArrowLeft size={20} /> Back</button>
      <div className="subview-content">
        <h4>Saved Addresses</h4>
        <div className="address-list">
          {addresses.length > 0 ? addresses.map(addr => (
            <div key={addr.id} className="address-card">
              <div className="address-card-header">
                <strong>{addr.type || 'Home'}</strong>
                <div className="address-actions">
                  <button onClick={() => openAddressModal(addr)} className="icon-btn edit"><Edit2 size={16}/></button>
                  <button onClick={() => handleDeleteAddress(addr.id)} className="icon-btn delete"><Trash2 size={16}/></button>
                </div>
              </div>
              <p>{addr.street}, {addr.city}, {addr.state}</p>
              <p>Pincode: {addr.pincode}</p>
            </div>
          )) : <p className="empty-text">No saved addresses yet.</p>}
        </div>
        <button className="add-action-btn" onClick={() => openAddressModal(null)}>
          <Plus size={20} /> Add New Address
        </button>
      </div>
    </div>
  );

  const renderOrders = () => (
    <div className="sidebar-subview">
      <button className="back-btn" onClick={() => setActiveView('menu')}><ArrowLeft size={20} /> Back</button>
      <div className="subview-content">
        <h4>Order History</h4>
        <div className="orders-list">
          {loading ? (
            <p className="empty-text">Fetching your orders...</p>
          ) : orders.length > 0 ? orders.map(order => (
            <div key={order.id} className="order-history-card">
              <div className="order-card-header">
                <span className="order-number">{order.orderId}</span>
                <span className="order-date">{new Date(order.createdAt).toLocaleDateString()}</span>
              </div>

              {/* Tracker Component */}
              <OrderTracker status={order.status} />

              <div className="order-card-footer">
                <span className="order-amount">₹{order.amount.toFixed(2)}</span>
                <button 
                  className="simulate-btn"
                  onClick={() => simulateStatus(order.id)}
                >
                  <Truck size={12} /> Simulate Transit
                </button>
              </div>
            </div>
          )) : <p className="empty-text">No orders found.</p>}
        </div>
      </div>
    </div>
  );

  return (
    <>
      <div className={`sidebar-overlay ${isOpen ? 'active' : ''}`} onClick={onClose} />
      <div className={`user-sidebar ${isOpen ? 'active' : ''}`}>
        <div className="sidebar-header">
          <button className="close-btn" onClick={onClose}><X size={24} /></button>
          <div className="user-info">
            <div className="user-avatar"><User size={32} color="#fff" /></div>
            <h3>{user ? user.username : 'Welcome back!'}</h3>
            <p>{user ? user.email : 'Heritage Premium Member'}</p>
          </div>
        </div>
        {activeView === 'menu' && renderMenu()}
        {activeView === 'addresses' && renderAddresses()}
        {activeView === 'orders' && renderOrders()}
      </div>
      <AddressModal
        isOpen={isAddressModalOpen}
        onClose={() => setIsAddressModalOpen(false)}
        initialData={addressModalData}
        onSave={handleAddressModalSave}
      />
      <ProfileModal
        isOpen={isProfileModalOpen}
        onClose={() => setIsProfileModalOpen(false)}
        user={user}
        onUpdateSuccess={handleProfileUpdateSuccess}
      />
    </>
  );
};

export default React.memo(UserSidebar);
